import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Login from './pages+/Login';
import Inventario from './pages/Inventario';

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/inventario" element={<Inventario />} />
      </Routes>
    </Router>
  );
}
